import re
import json
import urllib.request
import urllib.parse
import base64
from langflow.custom import Component
from langflow.io import MessageInput, StrInput, SecretStrInput, Output
from langflow.schema import Data, Message

class UniversalConfluenceFetcher(Component):
    display_name = "Custom Confluence Fetcher"
    description = "Parses a Confluence URL dynamically from Chat Input and fetches its content."
    icon = "Heading"

    inputs = [
        MessageInput(
            name="chat_message", 
            display_name="User URL (From Chat Input)", 
            input_types=["Message"],  # Matches Chat Input's output type perfectly
            info="Connect the Chat Input node here."
        ),
        StrInput(
            name="confluence_email", 
            display_name="Confluence Email/Username", 
            info="The email address associated with your Atlassian account."
        ),
        SecretStrInput(
            name="atlassian_api_token", 
            display_name="Atlassian API Token", 
            info="Your generated Atlassian API Token (not your account password)."
        )
    ]

    outputs = [
        Output(name="confluence_data", display_name="Confluence Data", method="fetch_content")
    ]

    def _extract_page_id(self, url: str) -> str:
        page_id_match = re.search(r"pageId=(\d+)", url)
        if page_id_match:
            return page_id_match.group(1)
        numeric_id_match = re.search(r"/pages/(\d+)", url)
        if numeric_id_match:
            return numeric_id_match.group(1)
        return ""

    def _extract_base_url(self, url: str) -> str:
        parsed = urllib.parse.urlparse(url)
        return f"{parsed.scheme}://{parsed.netloc}"

    def _clean_html(self, html_text: str) -> str:
        clean = re.sub(r'<[^>]+>', ' ', html_text)
        clean = re.sub(r'\s+', ' ', clean)
        return clean.strip()

    def fetch_content(self) -> Data:
        # Extract the raw string out of the incoming Langflow Message object
        url_str = ""
        if hasattr(self.chat_message, "text") and self.chat_message.text:
            url_str = self.chat_message.text.strip()
        elif isinstance(self.chat_message, str):
            url_str = self.chat_message.strip()

        page_id = self._extract_page_id(url_str)
        base_domain = self._extract_base_url(url_str)

        if not page_id:
            return Data(text="Error: Could not extract a valid Page ID from the provided Confluence URL.")
        if not self.confluence_email or not self.atlassian_api_token:
            return Data(text="Error: Missing Confluence credentials. Provide both email and token fields.")

        api_endpoint = f"{base_domain}/wiki/rest/api/content/{page_id}?expand=body.storage,title"
        
        try:
            auth_str = f"{self.confluence_email}:{self.atlassian_api_token}"
            encoded_auth = base64.b64encode(auth_str.encode('utf-8')).decode('utf-8')
            
            req = urllib.request.Request(api_endpoint)
            req.add_header("Authorization", f"Basic {encoded_auth}")
            req.add_header("Accept", "application/json")
            
            with urllib.request.urlopen(req) as response:
                if response.status == 200:
                    data = json.loads(response.read().decode('utf-8'))
                    page_title = data.get("title", "Untitled Page")
                    raw_body = data.get("body", {}).get("storage", {}).get("value", "")
                    cleaned_body = self._clean_html(raw_body)
                    
                    combined_output = f"Document Title: {page_title}\n\nDocument Content:\n{cleaned_body}"
                    return Data(text=combined_output)
                else:
                    return Data(text=f"API Request Failed with status code: {response.status}")
        except Exception as e:
            return Data(text=f"Failed to fetch Confluence details. Exception: {str(e)}")

import httpx
from langchain_openai import ChatOpenAI
from pydantic.v1 import SecretStr

from lfx.base.models.model import LCModelComponent
from lfx.field_typing import LanguageModel
from lfx.field_typing.range_spec import RangeSpec
from lfx.inputs.inputs import DropdownInput, IntInput, SecretStrInput, SliderInput, StrInput


class OpenRouterComponent(LCModelComponent):
    """OpenRouter API component for language models."""

    display_name = "OpenRouter"
    description = (
        "OpenRouter provides unified access to multiple AI models from different providers through a single API."
    )
    icon = "OpenRouter"

    inputs = [
        *LCModelComponent.get_base_inputs(),
        SecretStrInput(name="api_key", display_name="API Key", required=True),
        DropdownInput(
            name="model_name",
            display_name="Model",
            options=[],
            value="",
            refresh_button=True,
            real_time_refresh=True,
            required=True,
        ),
        SliderInput(
            name="temperature",
            display_name="Temperature",
            value=0.7,
            range_spec=RangeSpec(min=0, max=2, step=0.01),
            advanced=True,
        ),
        IntInput(name="max_tokens", display_name="Max Tokens", advanced=True),
        StrInput(name="site_url", display_name="Site URL", advanced=True),
        StrInput(name="app_name", display_name="App Name", advanced=True),
    ]

    def fetch_models(self) -> list[dict]:
        """Fetch available models from OpenRouter."""
        try:
            response = httpx.get("https://openrouter.ai/api/v1/models", timeout=10.0)
            response.raise_for_status()
            models = response.json().get("data", [])
            return sorted(
                [
                    {
                        "id": m["id"],
                        "name": m.get("name", m["id"]),
                        "context": m.get("context_length", 0),
                    }
                    for m in models
                    if m.get("id")
                ],
                key=lambda x: x["name"],
            )
        except (httpx.RequestError, httpx.HTTPStatusError) as e:
            self.log(f"Error fetching models: {e}")
            return []

    def update_build_config(self, build_config: dict, field_value: str, field_name: str | None = None) -> dict:  # noqa: ARG002
        """Update model options."""
        models = self.fetch_models()
        if models:
            build_config["model_name"]["options"] = [m["id"] for m in models]
            build_config["model_name"]["tooltips"] = {m["id"]: f"{m['name']} ({m['context']:,} tokens)" for m in models}
        else:
            build_config["model_name"]["options"] = ["Failed to load models"]
            build_config["model_name"]["value"] = "Failed to load models"
        return build_config

    def build_model(self) -> LanguageModel:
        """Build the OpenRouter model."""
        if not self.api_key:
            msg = "API key is required"
            raise ValueError(msg)
        if not self.model_name or self.model_name == "Loading...":
            msg = "Please select a model"
            raise ValueError(msg)

        kwargs = {
            "model": self.model_name,
            "openai_api_key": SecretStr(self.api_key).get_secret_value(),
            "openai_api_base": "https://openrouter.ai/api/v1",
            "temperature": self.temperature if self.temperature is not None else 0.7,
        }

        if self.max_tokens:
            kwargs["max_tokens"] = int(self.max_tokens)

        headers = {}
        if self.site_url:
            headers["HTTP-Referer"] = self.site_url
        if self.app_name:
            headers["X-Title"] = self.app_name
        if headers:
            kwargs["default_headers"] = headers

        return ChatOpenAI(**kwargs)
